class ApiClient {
  static const String baseUrl = 'https://api.example.com';
  String? _authToken;
  final http.Client _client = http.Client();

  Future<Map<String, dynamic>> authenticate(String username, String password) async {
    try {
      final response = await _client.post(
        Uri.parse('$baseUrl/auth/login'),
        headers: {
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'username': username,
          'password': password,
        }),
      ).timeout(const Duration(seconds: 10));

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body) as Map<String, dynamic>;
        _authToken = data['token'] as String?;
        return data;
      } else {
        throw Exception('Authentication failed: ${response.statusCode}');
      }
    } on TimeoutException {
      throw Exception('Request timeout');
    } catch (e) {
      throw Exception('Authentication error: $e');
    }
  }

  Future<Map<String, dynamic>> getUserProfile() async {
    if (_authToken == null) {
      throw Exception('Not authenticated');
    }

    try {
      final response = await _client.get(
        Uri.parse('$baseUrl/user/profile'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
      ).timeout(const Duration(seconds: 10));

      if (response.statusCode == 200) {
        return jsonDecode(response.body) as Map<String, dynamic>;
      } else if (response.statusCode == 401) {
        _authToken = null;
        throw Exception('Unauthorized - token expired');
      } else {
        throw Exception('Failed to fetch profile: ${response.statusCode}');
      }
    } on TimeoutException {
      throw Exception('Request timeout');
    } catch (e) {
      throw Exception('Profile fetch error: $e');
    }
  }

  Future<Map<String, dynamic>> updateUserProfile(Map<String, dynamic> profileData) async {
    if (_authToken == null) {
      throw Exception('Not authenticated');
    }

    try {
      final response = await _client.put(
        Uri.parse('$baseUrl/user/profile'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
        body: jsonEncode(profileData),
      ).timeout(const Duration(seconds: 10));

      if (response.statusCode == 200) {
        return jsonDecode(response.body) as Map<String, dynamic>;
      } else if (response.statusCode == 401) {
        _authToken = null;
        throw Exception('Unauthorized - token expired');
      } else {
        throw Exception('Failed to update profile: ${response.statusCode}');
      }
    } on TimeoutException {
      throw Exception('Request timeout');
    } catch (e) {
      throw Exception('Profile update error: $e');
    }
  }

  Future<List<dynamic>> syncData() async {
    if (_authToken == null) {
      throw Exception('Not authenticated');
    }

    try {
      final response = await _client.get(
        Uri.parse('$baseUrl/sync/data'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
      ).timeout(const Duration(seconds: 15));

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data['items'] as List<dynamic>;
      } else if (response.statusCode == 401) {
        _authToken = null;
        throw Exception('Unauthorized - token expired');
      } else {
        throw Exception('Failed to sync data: ${response.statusCode}');
      }
    } on TimeoutException {
      throw Exception('Request timeout');
    } catch (e) {
      throw Exception('Data sync error: $e');
    }
  }

  Future<Map<String, dynamic>> uploadData(List<Map<String, dynamic>> items) async {
    if (_authToken == null) {
      throw Exception('Not authenticated');
    }

    try {
      final response = await _client.post(
        Uri.parse('$baseUrl/sync/upload'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_authToken',
        },
        body: jsonEncode({'items': items}),
      ).timeout(const Duration(seconds: 15));

      if (response.statusCode == 200) {
        return jsonDecode(response.body) as Map<String, dynamic>;
      } else if (response.statusCode == 401) {
        _authToken = null;
        throw Exception('Unauthorized - token expired');
      } else {
        throw Exception('Failed to upload data: ${response.statusCode}');
      }
    } on TimeoutException {
      throw Exception('Request timeout');
    } catch (e) {
      throw Exception('Data upload error: $e');
    }
  }

  void logout() {
    _authToken = null;
  }

  bool get isAuthenticated => _authToken != null;

  void dispose() {
    _client.close();
  }
}

